def clamp(value: int, low: int, high: int) -> int {
    if value < low {
        return low;
    }
    if value > high {
        return high;
    }
    return value;
}

with entry {
    print(clamp(12, 0, 10));
}

node Product {
    has name: str;
    has price: float;

    def discounted(rate: float) -> float {
        return self.price - (self.price * rate);
    }
}

with entry {
    item = Product(name="Notebook", price=5.0);
    print(item.discounted(0.2));
}

