walker Tally {
    has total: int = 0;

    def record(value: int) {
        if value > 0 {
            self.total = self.total + value;
        }
    }
}

with entry {
    tally = Tally();
    tally.record(3);
    tally.record(-2);
    tally.record(4);
    print(tally.total);
}

def sum_even(limit: int) -> int {
    total: int = 0;
    current: int = 0;
    while current <= limit {
        if current % 2 == 0 {
            total = total + current;
        }
        current = current + 1;
    }
    return total;
}

with entry {
    print(sum_even(6));
}
